SELECT r.*, u.name AS reporter_name, CASE WHEN r.target_type = 'PRODUCT' THEN p.name WHEN r.target_type = 'REVIEW' THEN CONCAT('후기 #', rv.review_id) WHEN r.target_type = 'QNA' THEN q.title ELSE CONCAT('대상 #', r.target_id) END AS target_title FROM reports r JOIN users u ON u.user_id = r.reporter_id LEFT JOIN products p ON p.product_id = r.target_id AND r.target_type = 'PRODUCT' LEFT JOIN reviews rv ON rv.review_id = r.target_id AND r.target_type = 'REVIEW' LEFT JOIN qnas q ON q.qna_id = r.target_id AND r.target_type = 'QNA'
r.status = #{status}
AND r.reporter_id = #{user_id}
AND r.target_type = #{targetType}
AND r.target_id = #{target_id}
AND ( r.reason LIKE CONCAT("%", #{keyword} ,"%") OR u.name LIKE CONCAT("%", #{keyword} ,"%") )
AND r.created_at >= CONCAT(#{startDate}, ' 00:00:00')
AND r.created_at <= CONCAT(#{endDate}, ' 23:59:59')
ORDER BY r.created_at ASC, r.report_id ASC
ORDER BY r.target_type ASC, r.target_id ASC, r.report_id DESC
ORDER BY r.created_at DESC, r.report_id DESC
LIMIT #{size} OFFSET #{offset}

SELECT count(*)
FROM reports r
JOIN users u ON u.user_id = r.reporter_id
LEFT JOIN products p ON p.product_id = r.target_id AND target_type = 'PRODUCT' 
LEFT JOIN reviews rv ON rv.review_id = r.target_id AND target_type = 'REVIEW'
LEFT JOIN qnas q ON q.qna_id = r.target_id AND target_type = 'QNA'


